+            let center = ((buf_w - view_w) / 2) as i32;
+            let max_src = (buf_w - view_w) as i32;
+            let src = (center + pan_x).clamp(0, max_src);
+            (src as u16, area.x, view_w)
+        } else {
+            let center = ((view_w - buf_w) / 2) as i32;
+            let min_dst = i32::from(area.x);
